            Toast.makeText(this, "Shared URL: $sharedText", Toast.LENGTH_LONG).show()
        }
    }

    private fun handleSharedImage(intent: Intent) {
        (intent.getParcelableExtra<android.net.Uri>(Intent.EXTRA_STREAM))?.let { imageUri ->
            // Process the shared image URI
